function LBattleMap:LBattleMap()
    self._isInitEvent = false                    -- 是否已初始化
    self._isInitMap = false

    self._arrayingTeamSide = 1 -- 左边队伍

    self._curTouchPoint = nil  --拖拽过程中当前的触摸点
    self._allTouchPointList = {} --拖拽过程所有触摸过的点
    self._teamADataList = {}
    self._teamBDataList = {}
    self._formationType = 1
    self._modelList = {}                --spine 列表
    self._isNeedRefreshHero = false        -- 地图没加载好，就收到英雄显示事件，需要延后刷新
    self._enemyHeroData = nil            -- 缓存的延后刷新的敌人数据

    ---@type LFormationGrid  @recommand 引用scene的一个实例
    self._formationGrid = nil
end

function LBattleMap:OnDestroy()
    if gLFightManager then
        gLFightManager:ClearAllBattle()
    end

    self:ClearAllModel()
    self:StopDelayShowModelTimer()

    LMapBase.OnDestroy(self)
end

function LBattleMap:OnCreate()
    LMapBase.OnCreate(self)

    self._formationGrid = self._parentScene:GetFormationGrid()

    self:MapEventRecv(EventNames.BATTLE_MAP_OFFSET, function(val, time, bUp)
        self:SetMapOffset(val)
        self:ResetCameraPos(time)
        if bUp and self._bNotShowModel then
            self:StartDelayShowModelTimer()
        end
    end)
    self:MapEventRecv(EventNames.BATTLE_MAP_BG_OFFSET, function(y)
        self:SetBgOffset(y)
    end)

    self._setCombatTypeFunc = function(type)
        self._combatType = type
    end

    self._setCombatTeamFunc = function(teamIndex)
        self._teamIndex = teamIndex
    end

    self._showBuffPop = function()
        self:ShowBuffPop()
    end

    self._exitAccountWnd = function(...)
        self:OnAccountExit(...)
    end

end

function LBattleMap:ChangeMapPrefab(mapName)
    self:SetMapName(mapName)
    self:StartLoadMap()
end

function LBattleMap:OnResetMap()
    local mapName = self:GetMapNameFromArg(self._argList)

    self:SetMapName(mapName)

    self._arrayingTeamSide = 1 -- 左边队伍

    self:ClearAllMap()
    self:ClearAllModel()

    --gLGameUI:CheckShowMainBottom()
    --gLGameUI:CheckShowMainTop()
end

function LBattleMap:IsBlurMap(argList)
    if not argList then
        argList = self._argList
    end

    local mapName = self:GetMapNameFromArg(argList)

    local isBlurMap = string.find(mapName, "Blur")

    return isBlurMap
end

function LBattleMap:GetMapNameFromArg(argList)
    local mapName = nil
    local isOnlySet = argList and argList["isOnlySet"]
    if not isOnlySet then
        local combatExtraData = argList["extraData"]
        mapName = combatExtraData.battleMapName
        --else
        --    local para = argList["para"]
        --    local targetType = para.setTargetType
        --    mapName = gModelBattle:GetBattleMapRes({combatType = targetType})
    end

    if not mapName then
        mapName = "MapBattle1001"
    end
    return mapName
end

function LBattleMap:OnExitMap()


    self._isReliefTroop = nil
    self._reliefTroopData = nil

    self._formationGrid:ShowGrid(false)
    self:ClearAllModel()
    self:StopDelayShowModelTimer()
    self._bNotShowModel = nil

    self._combatType = nil
    local isOnlySet = self:IsOnlySetState()
    if isOnlySet then
        self:MapEventRemove(EventNames.ON_CHANGE_BATTLE_TYPE, self._setCombatTypeFunc)
        self:MapEventRemove(EventNames.ON_CHANGE_BATTLE_TEAM, self._setCombatTeamFunc)
    else
        --退出战斗场景
        local combatType = self:GetCombatType()
        if gModelBattle:IsEndlessCombat(combatType) then
            self:MapEventRemove(EventNames.ON_ENDLESS_BUFF_SELECT, self._showBuffPop)
        end
        if gLFightManager ~= nil then
            local noNeedBackground = self:GetMapArg("noNeedBackground")
            if not noNeedBackground then
                printInfoN("LBattleMap:OnExitMap() ------- combatType = " .. tostring(combatType))
                gLFightManager:ResetTimeScale()

                if combatType == LCombatTypeConst.COMBAT_PK then
                    gLFightManager:SkipBattle(combatType)
                else
                    gLFightManager:TryChangeToBackground()
                end

                gLFightManager:ClearCombatByIfAllEnd(combatType)
            end
        end


    end

    self:MapEventRemove(EventNames.ON_EXIT_ACCOUNT_WND, self._exitAccountWnd)

    GF.CloseWndByName("UIFight")
    GF.CloseWndByName("UIFightPrepare")
    GF.CloseWndByName("UIFightSowWin")
    GF.CloseWndByName("UIEmFight")


end

function LBattleMap:OnMapReady()
    if not self._isInitEvent then
        self._isInitEvent = true
        self:InitEvent()
        self:InitMsg()
    end

    LMapBase.OnMapReady(self)
end

