function LBattleMap:ClearAllMap()
    self._isInitMap = false
end

function LBattleMap:ClearAllModel()
    for k, v in pairs(self._modelList or {}) do
        for k1, v1 in pairs(v) do
            v1:Destroy()
        end
    end
    self._modelList = {}
end

function LBattleMap:OnAccountExit(combatType, batRet)
    local mapCombatType = self:GetCombatType()
    if mapCombatType == LCombatTypeConst.COMBAT_BATTLE_VIDEO then
        local extraData = self:GetMapArg("extraData")
        if not extraData or extraData.combatType ~= combatType then
            return
        end
    else
        if mapCombatType ~= combatType then
            return
        end
    end

    local retFunc = gModelBattle:GetReturnFun(combatType)
    if retFunc then
        retFunc(batRet)
    end
end

function LBattleMap:ModifyBgPos()
    if not self:IsBlurMap() then return end

    local pos = self:GetDefaultCameraPos()
    local tran = CS.FindTrans(self._mapTrans, "LayerRoot/LayerBg/Bg")
    if CS.IsValidObject(tran) then
        tran.position = pos
    end
end

function LBattleMap:ModifyArray(isFight)
    if not self:IsBlurMap() then return end

    local arrayTran = CS.FindTrans(self._mapTrans, "LayerRoot/LayerBg/arrayRoot")
    CS.ShowObject(arrayTran, isFight)
end

