function LBattleMap:OnEnterMap()

    self._teamIndex = 0
    self:ModifyBgPos()

    self._arrayingTeamSide = 1 -- 左边队伍
    self._formationGrid:ShowGrid(false)
    self:ClearAllModel()

    self._isReliefTroop = nil
    self._reliefTroopData = nil

    local combatType = self:GetCombatType()

    gLFightManager:SetNowMapTrans(self:GetMapTrans())
    gLFightManager:SetFormationGrid(self._formationGrid)

    FireEvent(EventNames.ON_ENTER_BATTLE_MAP)
    -- 地图已经预备好了
    self._isInitMap = true

    self._bNotShowModel = nil

    local isOnlySet = self:IsOnlySetState()
    local wndPara = self:GetMapArg("para")
    if isOnlySet then
        self._formationGrid:SetFigureTransType(1)
        self:MapEventRecv(EventNames.ON_CHANGE_BATTLE_TYPE, self._setCombatTypeFunc)
        --self:MapEventRecv(EventNames.ON_CHANGE_CROSSGRADING_TEAMINDEX,self._setCrossGrdingIndexFunc)
        self:MapEventRecv(EventNames.ON_CHANGE_BATTLE_TEAM, self._setCombatTeamFunc)
        self:ChangeShowStatus(true)
        GF.OpenWndBottom("UIFightPrepare", { wndType = wndPara.wndType, para = wndPara, combatType = combatType })
        self._bNotShowModel = true
    else
        if gModelBattle:IsEndlessCombat(combatType) then
            self:MapEventRecv(EventNames.ON_ENDLESS_BUFF_SELECT, self._showBuffPop)
        end

        local extraData = self:GetBattleExtraData()
        local isFight = self:IsFight()
        printInfoN(string.format("lbattlemap isFight %s", tostring(isFight)))
        self:ChangeShowStatus(not isFight)

        self:RegisterExitAccountWnd()
        if isFight then

            local isNew = extraData.isNew
            printInfoN(string.format("lbattlemap isNew %s", tostring(isNew)))
            if isNew then
                gLFightManager:DoActiveBattleStart()
            else
                local index = extraData.index
                gLFightManager:OnBackgroundToFront(combatType, index)
            end

            GF.OpenWndBottom("UIFight", { combatType = combatType, extraData = extraData })

            local exceptsWnd = {
                ["UIFight"] = true,
                ["UIBulletSay"] = true,
                ["UILvUp"] = true,
                ["UITaCutToEff"] = true,
                ["UIOrdinResult"] = true,
                ["UIringFightResult"] = true,
                ["WndCrossServerBattleResult"] = true,
                ["UIKuafuGradMatching"] = true,
                -- ["UIActFairCompeteReset"] = true,
                -- ["WndHighStageRaceBattleResult"] = true,
            }
            gLGameUI:CloseAllButExcept(exceptsWnd)
        else
            --打开据点展示界面
            if self:IsOpentBattleShow() then
                self._formationGrid:SetFigureTransType(2)

                GF.OpenWndBottom("UIFightSowWin", { extraData = extraData, combatType = combatType })
                self:InitBattleShowMonster()
                local boxList = self._formationGrid:GetFigureTransDataList(false)
                for i, v in pairs(boxList) do
                    local addSprite = v.addSprite
                    if addSprite then
                        self:SetBuildClick(addSprite, function()
                            gLFightManager:PrepareGoToBattle(combatType, { curTeam = i - 1 })
                        end)
                    end
                end

                self:ShowTeamHero()
                return
            end
            self._formationGrid:SetFigureTransType(1)
            self:InitReliefTroopData()

            if gModelBattle:IsMultiReportCombatType(combatType) then
                GF.OpenWnd("UIMultiFightPre", { combatType = combatType, extraData = extraData, para = wndPara })
            elseif gModelBattle:IsNewReportCombatType(combatType) then
                GF.OpenWnd("UIEmFight", { extraData = extraData })
            else
                GF.OpenWnd("UIFightPrepare", { wndType = 1, extraData = extraData, combatType = combatType })
            end

            self._bNotShowModel = true
            self:RefreshTeamATactical()

            local monsterRefId = gModelBattle:GetMonsterId(combatType, self:GetBattleExtraData())
            if monsterRefId > 0 then
                self:RefreshMonster(monsterRefId, nil, combatType)
            end
            if combatType == LCombatTypeConst.COMBAT_WONDERLAND then
                self:ShowWonderBoss()
            elseif combatType == LCombatTypeConst.COMBAT_DESIRETRAIL then
                self:ShowDesireTrailBoss()
            elseif gModelBattle:IsTimeCorridorCombat(combatType) then
                self:ShowWonderBoss()
            elseif combatType == LCombatTypeConst.COMBAT_TEST_BATTLE then
                self:ShowTestBattleFormation()
            elseif combatType == LCombatTypeConst.COMBAT_INVASION then
                self:ShowInvasionBoss()
            elseif (combatType == LCombatTypeConst.COMBAT_TACTICAL_SIMULATION or combatType == LCombatTypeConst.COMBAT_TACTICAL_SIMULATION_2) and extraData.targetId == 3 then
                --镜像模拟
                self:ShowMirrorSimu()
            elseif combatType == LCombatTypeConst.COMBAT_DREAMTRIP then
                self:ShowDreamTripMonster()

            elseif combatType == LCombatTypeConst.COMBAT_TYPE_44 then
                if extraData.monsterA and extraData.monsterA > 0 then
                    self:RefreshMonster(extraData.monsterA, false, LCombatTypeConst.COMBAT_TYPE_44)
                end
            end
            --
            if extraData.isUseCombatHeroData then
                self._formationGrid:RefreshShowFormationGridBg(extraData.combatHeroData:GetGrids(), true)
                local enemyHeroData = self._enemyHeroData
            end

            --需要重新刷新英雄吗
            if self._isNeedRefreshHero then
                self._isNeedRefreshHero = false
                local enemyHeroData = self._enemyHeroData
                self:RefreshMyHeroFormation()
                if enemyHeroData then
                    self:RefreshEnemy(enemyHeroData)
                end

                self._enemyHeroData = nil
            end
        end
    end


end

function LBattleMap:RegisterExitAccountWnd()
    self:MapEventRemove(EventNames.ON_EXIT_ACCOUNT_WND, self._exitAccountWnd)
    self:MapEventRecv(EventNames.ON_EXIT_ACCOUNT_WND, self._exitAccountWnd)
end

