function LBattleMap:InitEvent()
    self:MapEventRecv(EventNames.SCENE_ARRAYING_FORMATION_CHANGE, function(teamSide)
        self:SwitchArrayingTeamSide(teamSide)
        self:OnArrayingTeamSideChange()
    end)

    self:MapEventRecv(EventNames.Change_Hero_Matrix, function(formationType)
        if self:IsArrayingTeamLeft() then
            self:RefreshTeamATactical(formationType)
        else
            self:RefreshTeamBTactical(formationType)
        end
    end)
    self:MapEventRecv(EventNames.Scene_Hero_GoTo, function(key, pos, isUp, isMon, heroInfo)
        -- key = 英雄的id, pos = 对应的位置, isUp = 是否上阵
        -- 方法只有在上阵界面调用
        self:ShowSpineCommon(key, pos, isUp, isMon, heroInfo)
    end)

    self:MapEventRecv(EventNames.START_BATTLE, function()
        self:OnBattleStart()
    end)
    self:MapEventRecv(EventNames.REFRESH_MY_HERO_SHOW, function(...)
        self:RefreshMyHeroShow(...)
    end)
    self:MapEventRecv(EventNames.REFRESH_ENEMY_HERO_SHOW, function(heroData)
        self:RefreshEnemy(heroData)
    end)
    self:MapEventRecv(EventNames.REFRESH_ENEMY_BOSSTOWERHERO_SHOW, function(heroData)
        self:RefreshBossTowerEnemy(heroData)
    end)
    self:MapEventRecv(EventNames.ONE_KEY_FORMATION, function(...)
        self:OnOneKeyFormation(...)
    end)

    self:MapEventRecv(EventNames.ON_CHANGE_PREPARE_INDEX, function(...)
        self:ChangePrepareIndex(...)
    end)
    -- self:MapEventRecv(EventNames.ON_CHANGE_PREPARE_MONSTER,function (...)
    --     self:ChangePrepareMonster(...)
    -- end)

    self:MapEventRecv(EventNames.REFRESH_LEFT_TEMP_HERO, function(formationData, sid)
        self:ShowTempLeftHero(formationData, sid)
    end)

    self:MapEventRecv(EventNames.REFRESH_BATTLE_TEAM_SHOW, function()
        self:ShowTeamHero()
    end)
    self:MapNetRecv(LProtoIds.MonsterPowerResp, function(pb)
        local reqIndex = pb.reqIndex
        if reqIndex ~= ModelFormation.REQ_INDEX_TYPE_1 then return end

        local monsterIds = {}
        local powers = {}
        local powerData = pb.powerData
        for i, v in ipairs(powerData) do
            table.insert(monsterIds, v.monsterId)
            table.insert(powers, v.power)
        end
        self:RefreshBattleShowMonster(monsterIds, powers)
    end)

    self:MapEventRecv(EventNames.REFRESH_FORMATION_SHOW, function(...)
        self:RefreshFormationShow(...)
    end)

    self:MapEventRecv(EventNames.REFRESH_MONSTER_SHOW, function(matrixRefId, monsterIds, powers)
        matrixRefId = matrixRefId or 1
        monsterIds = monsterIds or {}
        powers = powers or 0
        self:SetBattleShowMonsterNew(matrixRefId, monsterIds, powers)
    end)
end

function LBattleMap:ShowTeamHero()
    self:RefreshTeamATactical(1)
    self._formationGrid:ResetLeftTypeTwo()

    local combatType = self:GetCombatType()
    local list = gModelFormation:GetFormationList(combatType)
    if not list then return end

    local formationGrid = self._formationGrid

    local dataList = {}
    for i, v in pairs(list) do
        local grids = v.grids
        if grids then
            local gIndex = 1
            local gGrid = 9
            for j, k in ipairs(grids) do
                local grid = k.grid
                if grid < gGrid then
                    gGrid = grid
                    gIndex = j
                end
            end
            local grid = grids[gIndex]
            if grid then
                local heroId = grid.id
                local index = i + 1
                local heroData = self:GenerateHeroData(combatType, heroId, index, formationGrid, true)
                heroData.power = v.power or 0
                dataList[index] = heroData
            end

        end
    end

    self._teamADataList = dataList

    self:ShowAllModels(dataList, true)
end

function LBattleMap:ShowTempLeftHero(formationData, sid)
    local combatType = self:GetCombatType()
    local formationRefId = formationData.arrayId
    -- local isBossTowerCombat = gModelBossTower:IsBossTowerCombat(combatType)
    local heroDataList = {}
    local formationGrid = self._formationGrid
    for k, v in pairs(formationData.idToIndex) do
        local heroId = k
        local index = v
        -- if isBossTowerCombat then
        --     heroDataList[index] = self:GenerateHeroData(combatType, tonumber(heroId), index, formationGrid, true,sid)
        -- else
        heroDataList[index] = self:GenerateHeroData(combatType, heroId, index, formationGrid, true)
        -- end
    end

    self._teamADataList = heroDataList

    self:RefreshTeamATactical(formationRefId)

    self._formationGrid:ResetFigureShow(false)

    self:ShowAllModels(heroDataList, true)
end

function LBattleMap:ShowBuffPop()
