function LBattleMap:IsFight()
    local isOnlySet = self:IsOnlySetState()
    if isOnlySet then return false end

    local isFight = gLFightManager:IsCombatTypeInFight(self:GetCombatType())
    return isFight

end
-- 一开始显示状态，是否在战斗判断，如果是在战斗则所有隐藏，如果不是在战斗，则显示
function LBattleMap:ChangeShowStatus(isPrepare)
    if isPrepare then
        self._formationGrid:ResetAllFigureShow()
    end
    self._formationGrid:ShowGrid(isPrepare)
    self._formationGrid:ShowFigureB(not self:IsOnlySetState())
    self:ClearAllModel()

    self:ModifyArray(not isPrepare)
end

