---测试战斗 编辑的队伍改变
function LBattleMap:OnArrayingTeamSideChange()
    local modelList = self._modelList
    for k, spineList in pairs(modelList) do
        local bEnable = (k == self._arrayingTeamSide)
        for m, fmtObject in pairs(spineList) do
            fmtObject:EnableTouch(bEnable)
        end
    end
end

---测试战斗 使用的队形
function LBattleMap:ShowTestBattleFormation()
    local extraData = self:GetBattleExtraData()
    if extraData.monsterA then
        self:RefreshMonster(extraData.monsterA, true)
    else
        local formation = LFightTest.GetFormationData(1) or {}
        local heroDataList, formationRefId = self:FormatShowDataList(formation, true)

        self._teamADataList = heroDataList
        self:RefreshTeamATactical(formationRefId)
        self:ShowAllModels(self._teamADataList, true)
    end

    if extraData.monsterB then
        self:RefreshMonster(extraData.monsterB)
    else
        local formation = LFightTest.GetFormationData(2) or {}
        local heroDataList, formationRefId = self:FormatShowDataList(formation, false)
        self._teamBDataList = heroDataList
        self:RefreshTeamBTactical(formationRefId)
        self:ShowAllModels(self._teamBDataList, false)
    end
end

function LBattleMap:ShowMirrorSimu()
    local formation = gModelCareSchool:GetMirrorFormationData(1) or {}
    local heroDataList, formationRefId = self:FormatShowDataList(formation, true)
    self._teamADataList = heroDataList
    self:RefreshTeamATactical(formationRefId)
    self:ShowAllModels(self._teamADataList, true)

    local formation = gModelCareSchool:GetMirrorFormationData(2) or {}
    local heroDataList, formationRefId = self:FormatShowDataList(formation, false)
    self._teamBDataList = heroDataList
    self:RefreshTeamBTactical(formationRefId)
    self:ShowAllModels(self._teamBDataList, false)
end

function LBattleMap:ShowDreamTripMonster()
    local extraData = self:GetBattleExtraData()
    if not extraData then return end

    local bossId = extraData.bossId
    if not bossId then return end

    local monsterLv
    local monsterAddCost = extraData.monsterAddCost
    if monsterAddCost and monsterAddCost > 0 then
        local addCostRef = gModelHeroExtra:GetMonsterAttrCostRef(monsterAddCost)
        if addCostRef then
            monsterLv = addCostRef.lv
        end
    end
    local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(bossId)
    if not monsterFormationRef then return end

    local formationGrid = self._formationGrid

    self:RefreshTeamBTactical(monsterFormationRef.formation)

    local combatType = self:GetCombatType()
    local tab = {
        monsterFormationRef.monster1, monsterFormationRef.monster2, monsterFormationRef.monster3, monsterFormationRef.monster4,
        monsterFormationRef.monster5, monsterFormationRef.monster6, monsterFormationRef.monster7, monsterFormationRef.monster8,
        monsterFormationRef.monster9, monsterFormationRef.monster10,
    }
    local monsterList = {}
    local tMonsterRef
    local index = 1
    for i, v in ipairs(tab) do
        if v ~= 0 then
            tMonsterRef = GameTable.MonsterAttrRef[v]
            if tMonsterRef then
                monsterList[index] = self:GenerateHeroData(combatType, v, index, formationGrid, false, {
                    monsterLv = monsterLv
                })
                index = index + 1
            end
        end
    end
    self._teamBDataList = monsterList
    self:ShowAllModels(self._teamBDataList, false)
end

function LBattleMap:FormatShowDataList(formation, isLeft)
    local combatType = self:GetCombatType()
    local formationGrid = self._formationGrid
    local formationRefId = formation.formationRefId or 0
    if formationRefId == 0 then
        formationRefId = 1
    end
    local heroDataList = {}
    for k, v in pairs(formation.grids or {}) do
        local heroId = v.id
        local serData = gModelHero:GetHeroById(heroId)
        local isExist = serData ~= nil
        if isExist then
            local index = gModelFormation:GetIndexByPos(formationRefId, v.grid)
            heroDataList[index] = self:GenerateHeroData(combatType, heroId, index, formationGrid, isLeft)
        end
    end

    return heroDataList, formationRefId
end

-------------------------------------------------------------------
function LBattleMap:InitReliefTroopData()
    gModelBattle:ClearReliefTroopCacheData()
    self._isReliefTroop = nil
    self._reliefTroopData = nil
    self._isReliefTroop, self._reliefTroopData = gModelBattle:GetReliefTroopData(self:GetCombatType(), self:GetBattleExtraData())
end

function LBattleMap:RefreshMyHeroShow(formation)
    self._cacheFormation = formation
    if not self._isInitMap then
        self._isNeedRefreshHero = true
        return
    end

    self:RefreshMyHeroFormation()
end

function LBattleMap:RefreshMyHeroFormation()
    local teamIndex = self._teamIndex or 0
    local combatType = self:GetCombatType()

    local extraData = self:GetBattleExtraData()
    if combatType == LCombatTypeConst.COMBAT_TEST_BATTLE and extraData.monsterA then return end

    local heroDataList = {}
    local formationRefId
    --援军阵型
    if self._isReliefTroop then
        formationRefId = self._reliefTroopData.formation
        local reliefTroopData = self._reliefTroopData
        local formationGrid = self._formationGrid
        for i, v in ipairs(reliefTroopData.monList) do
            local index = v.index
            heroDataList[index] = self:GenerateMonsterData(v.refId, index, formationGrid, true)
        end

        for i, v in ipairs(reliefTroopData.heroList) do
            local index = v.index
            heroDataList[index] = self:GenerateHeroData(combatType, v.id, index, formationGrid, true)
        end

        -- 【G公共支持】删除本命英雄功能
        -- if(combatType == LCombatTypeConst.COMBAT_TYPE_34)then
        --     local formationDataBy34 = gModelNaturalPartner:GemGetDestinyHeroGetFormation()
        --     local matrixRefId = formationDataBy34.formationRefId
        --     local grids34 = formationDataBy34.grids
        --     for i, v in ipairs(grids34) do
        --         local monRefId = tonumber(v.id)
        --         local index = v.grid
        --         local posIndex = gModelFormation:GetIndexByPos(matrixRefId,index)
        --         heroDataList[posIndex] = self:GenerateMonsterData(monRefId,posIndex,formationGrid,true)
        --     end
        -- end

    elseif combatType == LCombatTypeConst.COMBAT_TACTICAL_TRAINING then
        local extraData = self:GetBattleExtraData()
        heroDataList = gModelCareSchool:GetInitFromation(extraData.targetId, self._formationGrid)
    else
        local formation = self._cacheFormation or gModelFormation:GetFormation(combatType, teamIndex)
        local formationData = gModelFormation:GetMapFormationData(formation)
        formationRefId = formation and formation.formationRefId or 1

        local formationGrid = self._formationGrid
        for k, v in pairs(formationData) do
            local index = v.posIndex
            heroDataList[index] = self:GenerateHeroData(combatType, v.heroId, index, formationGrid, true)
        end
    end

    self._teamADataList = heroDataList

    if combatType == LCombatTypeConst.COMBAT_TACTICAL_TRAINING and nil == formationRefId then
    --空数据 的训练模式不触发
    else
        self:RefreshTeamATactical(formationRefId)
    end

    self._formationGrid:ResetFigureShow(false)

    self:ShowAllModels(heroDataList, true)

    if combatType == LCombatTypeConst.COMBAT_MAIN then
        --TODO
        --阵形依赖添加，让预制体不释放
    end
end

function LBattleMap:GenerateHeroData(combatType, heroId, posIndex, formationGrid, isLeft, params)
    params = params or {}
    local refId, level, star, isResonance, skin, curHp, maxHp, form
    local isMonster = false
    if combatType == LCombatTypeConst.COMBAT_WONDERLAND then
        local serData = gModelWonderland:GetHeroData(heroId)
        refId = serData.refId
        level = serData.lvl
        star = serData.star
        skin = serData.skin
        curHp = serData.curHp
        maxHp = serData.maxHp
        isResonance = serData.isResonance
        form = serData.form
    elseif combatType == LCombatTypeConst.COMBAT_DESIRETRAIL and not isLeft then
        local serData = gModelDesireTrail:GetHeroData(heroId)
        refId = serData.refId
        level = serData.lvl
        star = serData.star
        skin = serData.skin
        curHp = serData.curHp
        maxHp = serData.maxHp
        isResonance = serData.resonance
        form = serData.form

        --elseif gModelBattle:IsTimeCorridorCombat(combatType) then
        --    local serData = gModelTimeCorridor:GetHeroData(heroId)
        --    refId = serData.refId
        --    level = serData.lvl
        --    star = serData.star
        --    skin = serData.skin
        --    curHp = serData.curHp
        --    maxHp = serData.maxHp
        --    isResonance = serData.isResonance
        --    form = serData.form
    elseif gModelBattle:IsEndlessCombat(combatType) then
        local serData = gModelEndles:GetEndlessHeroData(combatType, heroId)
        refId = serData.refId
        level = serData.lv
        star = serData.star
        skin = serData.skin
        isResonance = serData.isResonance
        form = serData.form
    elseif combatType == LCombatTypeConst.COMBAT_TACTICAL_TRAINING then
        local ref = gModelHero:GetMonsterAttrByRefId(heroId)
        isMonster = true
        refId = ref.refId
        level = ref.lv
        star = ref.starLv
        skin = 0
        isResonance = 0
        -- elseif gModelBossTower:IsBossTowerCombat(combatType) then
        --     local ref = gModelBossTower:GetBossTowerHeroRefByRefId(heroId)
        --     if ref then
        --         local serverData
        --         if sid then
        --             serverData = gModelBossTower:GetBossTowerHeroDataByKeyAndRefId(sid,heroId)
        --         end
        --         local attr = ref.attr
        --         local monsterRef = gModelHero:GetMonsterAttrByRefId(attr)
        --         local tLv = serverData and serverData.breakLv or monsterRef.lv
        --         refId = monsterRef.refId
        --         isMonster = true
        --         level = tLv
        --         star = monsterRef.starLv
        --         skin = monsterRef.effectId
        --         isResonance = 0
        --     end
        -- elseif combatType == LCombatTypeConst.COMBAT_TYPE_33 then
        --     local tHeroId = tonumber(heroId)
        --     local ref = gModelFairCompete:GetFairCompeteHeroRefByRefId(tHeroId)
        --     if ref then
        --         local attr = ref.attr
        --         local monsterRef = gModelHero:GetMonsterAttrByRefId(attr)
        --         refId = monsterRef.refId
        --         isMonster = true
        --         level = monsterRef.lv
        --         star = monsterRef.starLv
        --         skin = monsterRef.effectId
        --         isResonance = 0
        --     end
    elseif combatType == LCombatTypeConst.COMBAT_DREAMTRIP and not isLeft then
        local tMonsterRef = GameTable.MonsterAttrRef[heroId]
        refId = heroId
        isMonster = true
        level = params.monsterLv or tMonsterRef.lv
        star = tMonsterRef.starLv
        isResonance = 0
    else
        local serData = gModelHero:GetHeroById(heroId)
        if not serData then
            printInfoNR("serData is a nil, heroId = " .. (heroId or "nil"))
            return
        end
        refId = serData:GetRefId()
        level = serData:GetLv()
        star = serData:GetStar()
        skin = serData:GetSkin()
        isResonance = serData:GetResonanceStatus()
        form = serData.form
    end

    local prefabName, needFlip, scale, bottomImg, race
    if not isMonster then
        prefabName, needFlip = gModelHero:GetHeroDisplay(refId, star, skin, not isLeft, form)
        scale = 1
        bottomImg = gModelHero:GetHeroBottomImgByRefId(refId)
        race = gModelHero:GetHeroRace(refId)
    else
        prefabName, scale, needFlip = gModelHero:GetMonsterPbNameByRefId(refId, not isLeft)
        --scale = scale * 0.8
        bottomImg = gModelHero:GetMonsterBottomImgByRefId(refId)
        race = gModelHero:GetMonsterRace(refId)
    end

    return {
        heroId = heroId,
        pbName = prefabName,
        bottomImg = bottomImg,
        pos = posIndex,
        race = race,
        level = level,
        scale = scale,
        root = formationGrid and formationGrid:GetFigureRoot(posIndex, not isLeft) or nil,
        isResonance = isResonance,
        refId = refId,
        star = star,
        curHp = curHp,
        maxHp = maxHp,
        isLeft = isLeft,
        needFlip = needFlip,
    }
end

-----------------------------------------------------------------
function LBattleMap:OnOneKeyFormation(list, sid)
    self._isOneKeyFormation = true
    self._oneKeyFormationIndex = 0
    self:RefreshFormationShow(list, sid)
end

function LBattleMap:RefreshFormationShow(list, sid)
    local isLeft = self:IsArrayingTeamLeft()
    local combatType = self:GetCombatType()
    local heroDataList = {}
    local formationGrid = self._formationGrid
    for heroId, index in pairs(list) do
        heroDataList[index] = self:GenerateHeroData(combatType, heroId, index, formationGrid, isLeft, sid)
        if self._isOneKeyFormation then
            self._oneKeyFormationIndex = self._oneKeyFormationIndex + 1
        end
    end

    if isLeft then
        self._teamADataList = heroDataList
    else
        self._teamBDataList = heroDataList
    end

    self._formationGrid:ResetFigureShow(not isLeft)
    self:ShowAllModels(heroDataList, isLeft)
end
-----------------------------------------------------------------
function LBattleMap:GenerateMonsterData(monsterAttrRefId, index, formationGrid, isLeft, combatType)
    local ref = gModelHero:GetMonsterAttrByRefId(monsterAttrRefId)
    if ref then
        local level = ref.lv
        if combatType == LCombatTypeConst.COMBAT_GUILD_BRAVE then
            local bossInfo = gModelGuildBoss:GetGuildBraveInfo()
            local difficultRef = gModelGuildBoss:GetNewGuildDungeonDifficultyRefByRefId(bossInfo.difficult)
            local monsterCostRef = GameTable.MonsterAttrCostRef[difficultRef.diffFixAttr]
            level = monsterCostRef.lv
        end
        local prefabName, scale, needFlip = gModelHero:GetMonsterPbNameByRefId(monsterAttrRefId, not isLeft)
        return {
            refId = monsterAttrRefId,
            star = gModelHero:GetHeroInitStarByRefId(monsterAttrRefId) or 0,
            pbName = prefabName,
            race = ref.raceType,
            scale = scale,
            root = formationGrid and formationGrid:GetFigureRoot(index, not isLeft) or nil,
            pos = index,
            bottomImg = gModelHero:GetMonsterBottomImgByRef(ref),
            level = level,
            isResonance = 0,
            isLeft = isLeft,
            needFlip = needFlip,
        }
    end
end
function LBattleMap:RefreshMonster(monsterRefId, isLeft, combatType)
    --CS.ShowObject(self._monsterRoot,true)
    local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(monsterRefId)

    if table.isempty(monsterFormationRef) then return end

    local matrixRefId = monsterFormationRef.formation
    if isLeft then
        self:RefreshTeamATactical(matrixRefId)
    else
        self:RefreshTeamBTactical(matrixRefId)

    end

    local tab = {
        monsterFormationRef.monster1,
        monsterFormationRef.monster2,
        monsterFormationRef.monster3,
        monsterFormationRef.monster4,
        monsterFormationRef.monster5,
        monsterFormationRef.monster6,
        monsterFormationRef.monster7,
        monsterFormationRef.monster8,
        monsterFormationRef.monster9, 
        monsterFormationRef.monster10,
    }
    --local index = 1
    local heroDataList = {}
    local formationGrid = self._formationGrid
    for i, v in ipairs(tab) do
        if v > 0 then
            local index = gModelFormation:GetIndexByPos(matrixRefId, i)
            heroDataList[index] = self:GenerateMonsterData(v, index, formationGrid, isLeft, combatType)
        end
    end 
    if isLeft then
        self._teamADataList = heroDataList
    else
        self._teamBDataList = heroDataList
    end

    self:ShowAllModels(heroDataList, isLeft)
end

function LBattleMap:ShowAllModels(data, isLeft)
    local index = isLeft and 1 or 2
    local spineList = self._modelList[index]
    if spineList then
        for k, v in pairs(spineList) do
            v:Destroy()
        end
    end
    spineList = {}
    self._modelList[index] = spineList

    --local heroDataList = data
    for k, v in pairs(data) do
        local pos = v.pos
        local dp = self:GenerateFormationObject(v, isLeft, pos, v.root, self._bNotShowModel)
        spineList[pos] = dp
        dp:StartLoad()
        self:RefreshModelShadow(pos, isLeft)
    end
end

function LBattleMap:RefreshEnemy(heroData)
    if not self._isInitMap then
        self._isNeedRefreshHero = true
        self._enemyHeroData = heroData
        return
    end

    if not heroData then return end

    CS.ShowObject(self._monsterRoot, true)

    local matrixRefId = heroData.matrixRefId
    self:RefreshTeamBTactical(matrixRefId)
    local heroCfgDataList = heroData.prefabNameList
    local heroDataList = {}
    local formationGrid = self._formationGrid
    for i, v in pairs(heroCfgDataList) do
        local index = v.pos
        heroDataList[index] = {
            pbName = v.prefabName,
            bottomImg = v.bottomImg,
            pos = index,
            root = formationGrid:GetFigureRoot(index, true),
            race = v.race,
            level = v.lv,
            star = v.star,
            refId = v.refId,
            scale = v.scale or 1,
            isResonance = v.isResonance,
            skin = v.skin,
            needFlip = v.needFlip,
        }
    end
    self._teamBDataList = heroDataList
    self:ShowAllModels(heroDataList, false)
end

function LBattleMap:RefreshBossTowerEnemy(heroData)
    if not self._isInitMap then
        self._isNeedRefreshHero = true
        self._enemyHeroData = heroData
        return
    end

    if not heroData then return end

    CS.ShowObject(self._monsterRoot, true)

    local matrixRefId = heroData.matrixRefId
    self:RefreshTeamBTactical(matrixRefId)
    local heroCfgDataList = heroData.prefabNameList
    local heroDataList = {}
    local formationGrid = self._formationGrid
    for i, v in pairs(heroCfgDataList) do
        local index = v.pos
        heroDataList[index] = {
            pbName = v.prefabName,
            bottomImg = v.bottomImg,
            pos = index,
            root = formationGrid:GetFigureRoot(index, true),
            race = v.race,
            star = v.star,
            refId = v.refId,
            level = v.lv,
            scale = (v.scale or 1) * 0.8,
            isResonance = v.isResonance,
            skin = v.skin,
            needFlip = v.needFlip,
        }
    end

    self._teamBDataList = heroDataList

    self:ShowAllModels(heroDataList, false)
end
