function LBattleMap:ShowWonderBoss()
    local combatExtraData = self:GetBattleExtraData()
    local bosses = combatExtraData.bossList or {}
    local grids = combatExtraData.grids
    local formationRefId = combatExtraData.formationRefId
    local heroData = {}
    heroData.matrixRefId = formationRefId
    local prefabNameList = {}
    for k, v in ipairs(bosses) do
        local grid = grids[k].grid
        local index = gModelFormation:GetIndexByPos(formationRefId, grid)
        --TODO 临时修改
        if index then
            if v.curHp > 0 then
                local refId = v.refId
                local prefabName
                local bottomImg
                local race
                local scale = 1
                local needFlip = false
                if v.heroType == ModelWonderland.ENEMY_MONSTER then
                    prefabName, scale, needFlip = gModelHero:GetMonsterPbNameByRefId(refId, true)
                    bottomImg = gModelHero:GetMonsterBottomImgByRefId(refId)
                    race = gModelHero:GetMonsterRace(refId)
                else
                    prefabName, needFlip = gModelHero:GetHeroDisplay(refId, v.star, v.skin, true, v.form)
                    bottomImg = gModelHero:GetHeroBottomImgByRefId(refId)
                    race = gModelHero:GetHeroRace(refId)
                end
                prefabNameList[index] = {
                    prefabName = prefabName,
                    bottomImg = bottomImg,
                    refId = refId,
                    lv = v.lvl,
                    race = race,
                    pos = index,
                    curHp = v.curHp,
                    maxHp = v.maxHp,
                    isResonance = v.isResonance or 0,
                    scale = scale,
                    needFlip = needFlip
                }
            end
        end
    end
    heroData.prefabNameList = prefabNameList
    self:RefreshEnemy(heroData)
end

