-----------------------------------------------------------------
function LBattleMap:GetCombatType()
    local isOnlySet = self:GetMapArg("isOnlySet")
    if isOnlySet then
        if not self._combatType then
            local para = self:GetMapArg("para")
            self._combatType = para.setTargetType
        end
        return self._combatType
    else
        local combatType = self:GetMapArg("combatType")
        return combatType
    end
end

function LBattleMap:IsOnlySetState()
    local onlySet = self:GetMapArg("isOnlySet")
    return onlySet
end

function LBattleMap:GetBattleExtraData()
    local extraData = self:GetMapArg("extraData")
    return extraData
end

function LBattleMap:IsOpentBattleShow()
    local extraData = self:GetBattleExtraData()
    if not extraData then return false end

    local isBattleShow = extraData.isBattleShow
    return isBattleShow
end

function LBattleMap:GetBattleShowLen(matrixRefId)
    local matrix = gModelFormation:GetFormationPosByRefId(matrixRefId)
    local list = {}
    if self:IsOpentBattleShow() then
        local _combatType = self:GetCombatType()
        local len = 5
        if _combatType == LCombatTypeConst.COMBAT_TYPE_75 then
            local monsterArr = gModelTower:GetTowerLayerMonstorLen(ModelTower.RACE_TYPE_99)
            len = #monsterArr
        end
        if len > 0 then
            for i = 1, len do
                table.insert(list, matrix[i])
            end
        end
    else
        list = matrix
    end
    return list
end

function LBattleMap:InitBattleShowMonster()
    local _combatType = self:GetCombatType()
    if _combatType == LCombatTypeConst.COMBAT_TYPE_75 then
        local monsterArr = gModelTower:GetTowerLayerMonstorLen(ModelTower.RACE_TYPE_99)
        gModelFormation:OnMonsterPowerReq(monsterArr, nil, _combatType, ModelFormation.REQ_INDEX_TYPE_1)
    end
end

function LBattleMap:RefreshBattleShowMonster(monsterArr, powers)
    local _combatType = self:GetCombatType()
    if _combatType == LCombatTypeConst.COMBAT_TYPE_75 then
        local matrixRefId = 1
        self:SetBattleShowMonster(matrixRefId, monsterArr, powers)
    end
end

function LBattleMap:SetBattleShowMonster(matrixRefId, monsterArr, powers)
    self:RefreshTeamBTactical(matrixRefId)
    local heroDataList = {}
    local formationGrid = self._formationGrid
    local gridMax = LCombatFormationConst.GRID_MAX
    for i, v in ipairs(monsterArr) do
        local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(tonumber(v))
        local showHeroId = 0
        local monsterIndex = 0
        for j = 1, gridMax do
            local monsterId = monsterFormationRef["monster" .. j]
            if monsterId > 0 then
                showHeroId = monsterId
                monsterIndex = monsterIndex + 1
                if monsterIndex >= 3 then
                    break
                end
            end
        end
        if showHeroId > 0 then
            local heroData = self:GenerateMonsterData(showHeroId, i, formationGrid, false)
            heroData.power = powers[i] or monsterFormationRef.monsterPower
            heroDataList[i] = heroData
            LxUiHelper.SetTransClick(heroData.root, function()
                GF.OpenWnd("UIFightSowMonsterPop", { monsterFormationId = tonumber(v) })
            end)
        end
    end
    self._teamBDataList = heroDataList
    self:ShowAllModels(heroDataList, false)
end

function LBattleMap:SetBattleShowMonsterNew(matrixRefId, monsterArr, powers)
    self:RefreshTeamBTactical(matrixRefId)
    local monsterFId = monsterArr[1]
    if not monsterFId then return end

    local heroDataList = {}
    local formationGrid = self._formationGrid
    monsterFId = tonumber(monsterFId)
    --for i, v in ipairs(monsterArr) do
    local index
    local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(monsterFId)
    --local showHeroId = 0
    --local monsterIndex = 0
    local gridMax = LCombatFormationConst.GRID_MAX
    for j = 1, gridMax do
        local monsterId = monsterFormationRef["monster" .. j]
        if monsterId > 0 then
            --showHeroId = monsterId
            --monsterIndex = monsterIndex + 1
            index = gModelFormation:GetIndexByPos(monsterFormationRef.formation, j)
            if index then
                local heroData = self:GenerateMonsterData(monsterId, index, formationGrid, false)
                --heroData.power = powers[i] or monsterFormationRef.monsterPower
                if heroData then
                    heroData.onClick = function()
                        GF.OpenWnd("UIFightSowMonsterPop", { monsterFormationId = monsterFId })
                    end
                end
                heroDataList[index] = heroData
                --LxUiHelper.SetTransClick(heroData.root, function ()
                --    GF.OpenWnd("UIFightSowMonsterPop",{monsterFormationId = tonumber(v)})
                --end)
            end
        end
    end
    --end
    self._teamBDataList = heroDataList
    self:ShowAllModels(heroDataList, false)
end

