function LBattleMap:IsArrayingTeamLeft()
    return self._arrayingTeamSide ~= 2
end

function LBattleMap:SwitchArrayingTeamSide(side)
    self._arrayingTeamSide = side
end

------------------------------------------------------------------
function LBattleMap:CheckReliefTroopSwapForbid(swapIndex)
    if self._isReliefTroop then
        --援军禁止交换限制
        if self._reliefTroopData.fixedIndex[swapIndex] then
            return true
        end
    end
    return false
end

-----------------------------------------------------------------
function LBattleMap:SwapHero(dpSpine)
    local isLeft = self:IsArrayingTeamLeft()
    self._allTouchPointList = {}
    self:SetBottomLight(self._curTouchPoint, isLeft, false)
    local pos, swapIndex = self:CheckTouchPoint(dpSpine, true)
    if swapIndex and self:CheckReliefTroopSwapForbid(swapIndex) then
        GF.ShowMessage(ccClientText(10157))
        return
    end

    if pos and swapIndex then
        self:SwapInfo(pos, swapIndex)
        local isBattleShow = self:IsOpentBattleShow()
        if isBattleShow then
            --如果是阵容显示界面 切换位置就调切换阵容协议
            local combatType = self:GetCombatType()
            gModelFormation:OnFormationExchangeReq(combatType, pos - 1, combatType, swapIndex - 1)
        end
        FireEvent(EventNames.ON_SWAP_PREPARE_OK)
    end
end

function LBattleMap:SwapInfo(beginPos, endPos)
    local isLeft = self:IsArrayingTeamLeft()
    local dataList = self._teamADataList
    if not isLeft then
        dataList = self._teamBDataList
    end

    local data1 = dataList[beginPos]
    local data2 = dataList[endPos]
    local spineList, sp1, sp2, beginParent, endParent
    local index = isLeft and 1 or 2
    spineList = self._modelList[index]
    sp1 = spineList[beginPos]
    sp2 = spineList[endPos]
    spineList[beginPos] = sp2
    spineList[endPos] = sp1
    beginParent = self._formationGrid:GetFigureRoot(beginPos, not isLeft)
    endParent = self._formationGrid:GetFigureRoot(endPos, not isLeft)

    local isSwap = false
    if sp1 then
        isSwap = true
        sp1:ChangeParentTrans(endParent)
        sp1:SetFormationPos(endPos)
        sp1:SetRenderOrder(5)
        --激活品质底座
        dataList[endPos] = data1
        self:ShowBottomShadow(endPos, isLeft)
    end
    if sp2 then
        isSwap = false
        sp2:ChangeParentTrans(beginParent)
        sp2:SetFormationPos(beginPos)
        sp2:SetRenderOrder(5)
        --激活品质底座
        dataList[beginPos] = data2
        self:ShowBottomShadow(beginPos, isLeft)
    end

    if isSwap then
        self:HideBottomShadow(beginPos, isLeft)
    end
    FireEvent(EventNames.Swap_Hero_Info, beginPos, endPos)
end
