--开灯
function LBattleMap:UpdatePoint(dpSpine, isOpen)
    local isLeft = self:IsArrayingTeamLeft()
    -- 超出距离关灯
    if self._curTouchPoint then
        local imgRange = 0.7
        local spineTrans = dpSpine:GetDisplayObject():GetSpineTrans()
        local dpPosition = spineTrans.position
        local matrix = isLeft and self._teamATacticalMatrix or self._teamBTacticalMatrix
        local dis = Vector2.Distance(dpPosition, self._formationGrid:GetGridPos(matrix[self._curTouchPoint], not isLeft))
        if dis > imgRange then
            self:SetBottomLight(self._curTouchPoint, isLeft, false)
            self._curTouchPoint = nil
        end
    end

    local pos, swapIndex = self:CheckTouchPoint(dpSpine, false)

    if pos and swapIndex then
        for i, v in ipairs(self._allTouchPointList) do
            self:SetBottomLight(v, isLeft, false)
        end
        table.insert(self._allTouchPointList, swapIndex)
        self._curTouchPoint = swapIndex
        self:SetBottomLight(self._curTouchPoint, isLeft, isOpen)
    elseif pos then
        self:SetBottomLight(pos, isLeft, false)
    end
end

--检查位置
function LBattleMap:CheckTouchPoint(dpSpine, isEndTouch, eventData)
    local pos = dpSpine:GetFormationPos()
    local spineTrans = dpSpine:GetDisplayObject():GetSpineTrans()
    local dpPosition = spineTrans.position + Vector3.New(0, 0.3, 0)

    if isEndTouch then
        --回复原来位置
        spineTrans.localPosition = Vector3(0, 0, 0)
    end

    local imgRange = 0.7
    local swapIndex = nil
    local isLeft = self:IsArrayingTeamLeft()
    local formationGrid = self._formationGrid:GetFormationGrid(not isLeft)
    local matrix = isLeft and self._teamATacticalMatrix or self._teamBTacticalMatrix
    for k, v in ipairs(matrix) do
        if k ~= pos or not isEndTouch then
            local gridPos = formationGrid[v]
            local dis = Vector2.Distance(dpPosition, gridPos)
            if dis <= imgRange then
                swapIndex = k
                break
            end
        end
    end
    local extraData = self:GetBattleExtraData()
    if isEndTouch and extraData and extraData.combatType == LCombatTypeConst.COMBAT_TACTICAL_TRAINING and swapIndex then
        local targetId = extraData.targetId
        local posList = gModelCareSchool:GetCheckPosListByRefId(targetId)
        if table.keysize(posList) > 0 then
            if posList[pos] or posList[swapIndex] then
                swapIndex = false
                GF.ShowMessage(ccClientText(20915))
            end
        end
    end

    if not swapIndex then
        return pos, false
    else
        return pos, swapIndex
    end
end

function LBattleMap:ShowSpineCommon(heroId, pos, isShow, isMon, heroInfo)
    local isLeft = self:IsArrayingTeamLeft()
    if not isShow then
        self:ClearSpine(pos, isLeft)
        return
    end
    local heroData
    if isMon then
        -- local combatType = self:GetCombatType()
        -- if gModelBossTower:IsBossTowerCombat(combatType) then
        --     local bossTowerRef = gModelBossTower:GetBossTowerHeroRefByRefId(heroId)
        --     local monsterRefId = bossTowerRef and bossTowerRef.attr
        --     heroData = self:GenerateMonsterData(monsterRefId, pos, nil, isLeft)
        -- else
        heroData = self:GenerateMonsterData(heroId, pos, nil, isLeft)
        -- end
    else
        local combatType = self:GetCombatType()
        heroData = self:GenerateHeroData(combatType, heroId, pos, nil, isLeft)
    end
    heroData.isLeft = isLeft
    if heroInfo then
        local power = heroInfo.power
        if power then
            heroData.power = power
        end
        local level = heroInfo.level
        if level then
            heroData.level = level
        end
    end

    self:ShowSpineInternal(heroData)
end

function LBattleMap:ClearSpine(pos, isLeft)
    local index = isLeft and 1 or 2
    local spineList = self._modelList[index]
    local spine = spineList[pos]
    if spine then
        spine:Destroy()
    end
    spineList[pos] = nil
    self:HideBottomShadow(pos, isLeft)
end

function LBattleMap:CheckOneKeyFormation()
    if not self._isOneKeyFormation then return end

    self._oneKeyFormationIndex = self._oneKeyFormationIndex - 1
    if self._oneKeyFormationIndex <= 0 then
        self._isOneKeyFormation = false
        FireEvent(EventNames.ON_PREPARE_OBJ_OK)
    end
end

function LBattleMap:GenerateFormationObject(data, isLeft, pos, root, bDelayShow)
    local side = isLeft and 1 or 2
    --local bEnabledTouch = (side == self._arrayingTeamSide)
    local scale = data.scale or 0.8
    local pbName = data.pbName
    if not pbName then return end

    local dp = LFormationObject:New()
    local bloodData = {
        race = data.race,
        level = data.level,
        isLeft = isLeft,
        pos = pos,
        curHp = data.curHp or 1,
        maxHp = data.maxHp or 1,
        isResonance = data.isResonance or 0,
        power = data.power,
        heroRefId = data.refId,
        star = data.star or 0
    }

    dp:SetObjectKey(pbName)
    dp:SetFormationPos(pos)
    local onClickFunc = function(...)
        if side == self._arrayingTeamSide then
            self:OnClickLeftHero(...)
        else
            if data.onClick then
                data.onClick(...)
            end
        end
    end;
    --if side == self._arrayingTeamSide then
    --    onClickFunc = function(...) self:OnClickLeftHero(...) end
    --else
    --    onClickFunc = data.onClick
    --end
    dp:SetClickFunc(onClickFunc)
    dp:CreateObject(root, pbName, scale, function()
        self:OnSpineLoaded(dp)
        self:CheckOneKeyFormation()
    end, bloodData)
    dp:SetVisible(not bDelayShow)

    dp:SetDirection(isLeft, data.needFlip)
    dp:SetSide(isLeft and 1 or 2)
    dp:EnableTouch(true)
    if bDelayShow then
        dp:SetDelayShow()
    end
    return dp
end

function LBattleMap:ShowSpineInternal(heroData)
    local pos = heroData.pos
    local isLeft = heroData.isLeft
    local pbName = heroData.pbName
    local index = isLeft and 1 or 2
    local spineList = self._modelList[index]
    if not spineList then
        spineList = {}
        self._modelList[index] = spineList
    end
    local spine = spineList[pos]
    local needNew = true
    if spine then
        local oldPrefabName = spine:GetObjectKey()
        local oldPos = spine:GetFormationPos()
        if oldPrefabName ~= pbName or oldPos ~= pos then
            spine:Destroy()
        else
            needNew = false
        end
    end

    if needNew then
        local root = self._formationGrid:GetFigureRoot(pos, not isLeft)
        local dp = self:GenerateFormationObject(heroData, isLeft, pos, root, self._bNotShowModel)
        spineList[pos] = dp
        dp:StartLoad()
    end

    if isLeft then
        self._teamADataList[pos] = heroData
    else
        self._teamBDataList[pos] = heroData
    end
    --激活品质底座
    self:RefreshModelShadow(pos, isLeft)
end

function LBattleMap:OnClickLeftHero(dp)
    local pos = dp:GetFormationPos()
    local side = dp:GetSide()
    local isBattleShow = self:IsOpentBattleShow()
    if isBattleShow then
        local combatType = self:GetCombatType()
        gLFightManager:PrepareGoToBattle(combatType, { curTeam = pos - 1 })
        return
    end

    local teamDataList = ((side == 1) and self._teamADataList or self._teamBDataList)
    local extraData = self:GetBattleExtraData()
    local downInfo = teamDataList and teamDataList[pos]
    -- if downInfo then
    --     local downId = downInfo.heroId
    --     local combatType = extraData and extraData.combatType
    -- if combatType and combatType == LCombatTypeConst.COMBAT_TYPE_33 and downId then
    --     local requiredHeroMap = extraData.requiredHeroMap
    --     -- if not requiredHeroMap then
    --     --     local sid = extraData.sid
    --     --     if sid then
    --     --         requiredHeroMap = gModelFairCompete:GetActivityRequireHeroMap(sid)
    --     --     end
    --     -- end
    --     requiredHeroMap = requiredHeroMap or {}
    --     if requiredHeroMap[downId] then
    --         GF.ShowMessage(ccClientText(37553))
    --         return
    --     end
    -- end
    -- end

    if self._isReliefTroop then
        --援军禁止下阵判断
        local teamData = teamDataList[pos]
        local fixedInFormation = self._reliefTroopData.fixedInFormation or {}
        local fixedKey = ""
        if teamData then
            fixedKey = teamData.heroId or teamData.refId
        end
        if fixedInFormation[fixedKey] then
            GF.ShowMessage(ccClientText(10156))
            return
        end
    end

    if side == 1 and extraData and extraData.combatType == LCombatTypeConst.COMBAT_TACTICAL_TRAINING then
        local targetId = extraData.targetId
        local posList = gModelCareSchool:GetCheckPosListByRefId(targetId)
        if table.keysize(posList) > 0 and posList[pos] then
            GF.ShowMessage(ccClientText(20915))
            return
        end
    end

    self:UpdatePoint(dp, false)
    self:ClearSpine(pos, side ~= 2)
    teamDataList[pos] = nil
    FireEvent(EventNames.Scene_Hero_Down, pos)
end

