            --        GF.ShowMessage(ccClientText(10156))
            --        return
            --    end
            --end
            --
            --if side == 1 and extraData and extraData.combatType == LCombatTypeConst.COMBAT_TACTICAL_TRAINING then
            --    local targetId = extraData.targetId
