            --self:UpdatePoint(dp,false)
            --self:ClearSpine(pos,side ~= 2)
            --teamDataList[pos] = nil
            --FireEvent(EventNames.Scene_Hero_Down, pos)
        end

        spineClick.onBeginDrag = function(eventData)
            if bForbidSwap then
                GF.ShowMessage(ccClientText(10157))
                return
            end
            dp:SetRenderOrder(9)
        end
        spineClick.onDrag = function(eventData)
            if bForbidSwap then return end
            if dp:GetSide() ~= self._arrayingTeamSide then return end

            local camera = gLGameScene:GetCurrentSceneCamera()
            local deltaPos = camera:ScreenToWorldPoint(eventData.position) - camera:ScreenToWorldPoint(eventData.position - eventData.delta)
            printInfoN(string.format("drag pos x: %s y: %s", eventData.position.x, eventData.position.y))
            dp:MoveLocalPosition(deltaPos)

