function LBattleMap:RefreshModelShadow(pos, isLeft)
    self:ShowBottomShadow(pos, isLeft)
end

function LBattleMap:ShowBottomShadow(pos, isLeft)
    local bottomImg = nil
    if isLeft then
        bottomImg = self._teamADataList[pos].bottomImg
    else
        bottomImg = self._teamBDataList[pos].bottomImg
    end
    self._formationGrid:ShowBottomShadow(pos, bottomImg, not isLeft)
end

function LBattleMap:HideBottomShadow(pos, isLeft)
    self._formationGrid:HideBottomShadow(pos, not isLeft)
end

