function LBattleMap:ShowMatrix(matrix, isRight)
    self._formationGrid:RefreshMatrix(matrix, isRight)
end

function LBattleMap:RefreshShowFormationGridBg(matrix, isRight)
    self._formationGrid:RefreshShowFormationGridBg(matrix, isRight)
end

-- 阵容刷新
function LBattleMap:RefreshTeamATactical(formationType)
    local matrixRefId = nil
    if formationType then
        matrixRefId = formationType
    else
        local combatType = self:GetCombatType()
        local formationRefId = gModelFormation:GetFormationMatrixRefId(combatType)
        if formationRefId then
            matrixRefId = formationRefId
        else
            matrixRefId = self._formationType
        end
    end

    self._formationType = matrixRefId

    local matrix = self:GetBattleShowLen(matrixRefId)
    local list = matrix
    local extraData = self:GetBattleExtraData()
    if extraData and extraData.combatType == LCombatTypeConst.COMBAT_TACTICAL_TRAINING then
        list = {}
        local targetId = extraData.targetId
        local _fList = gModelCareSchool:GetFormationListByRefId(targetId)
        for i, v in ipairs(matrix) do
            if _fList[i] then
                table.insert(list, v)
            end
        end
    end
    self._teamATacticalMatrix = list
    self:ShowMatrix(list, false)
    self:RefreshShowFormationGridBg(list, false)
end

-- 阵容刷新
function LBattleMap:RefreshTeamBTactical(matrixRefId)
    local matrix = self:GetBattleShowLen(matrixRefId)
    self._teamBTacticalMatrix = matrix
    self:ShowMatrix(matrix, true)

    --- 敌方布阵也要加不可上阵标记
    --[[    if self._combatType == LCombatTypeConst.COMBAT_TEST_BATTLE then
            self:RefreshShowFormationGridBg(matrix,true)
        end]]
    self:RefreshShowFormationGridBg(matrix, true)
end
