function LBattleMap:UpdateDelayShowModel()
    local spineList = self._modelList or {}
    for k, fList in pairs(spineList) do
        if fList then
            for m, spineCls in pairs(fList) do
                spineCls:DoDelayShow()
            end
        end
    end
    FireEvent(EventNames.ON_PREPARE_OBJ_OK)
end
