function LBattleMap:StartDelayShowModelTimer()
    self:StopDelayShowModelTimer()

    self._bNotShowModel = true
    self._delayShowModelTimer = LxTimer.DelayTimeCall(function()
        self._bNotShowModel = nil
        self._delayShowModelTimer = nil
        self:UpdateDelayShowModel()
    end, 0.4)
end

function LBattleMap:StopDelayShowModelTimer()
    if self._delayShowModelTimer then
        LxTimer.DelayTimeStop(self._delayShowModelTimer)
    end
end

function LBattleMap:IsReadyForCombat(combatType)
    if self:IsLoading() then return false end

    local curCombatType = self:GetCombatType()
    if curCombatType ~= combatType then return false end

    local isOnlySet = self:IsOnlySetState()
    if isOnlySet then return false end

    return true
end

function LBattleMap:IsInFight()
    return self:GetMapArg("isInFight") or false
end

function LBattleMap:GetFormationHero(grid)
    local list = self._modelList[1]
    local index = gModelFormation:GetIndexByPos(self._formationType, grid)
    if list then
        return list[index]
    end
end

